const raw = $input.first().json;

if (raw.input) {
  const parsed = typeof raw.input === 'string' ? JSON.parse(raw.input) : raw.input;
  return [{ json: parsed }];
}

return [{ json: raw }];

const linhas = $input.all();

const limites = {
  'aguardando proposta': 7,
  'compliance': 3,
  'minuta com cliente': 7,
  'juridico': 10,
  'fechamento': 3
};

const hoje = new Date();

const parseData = (data) => {
  if (!data) return null;
  const [dia, mes, ano] = data.split('/');
  return new Date(`${ano}-${mes}-${dia}`);
};

const resultado = linhas.map(item => {
  const d = item.json;

  const status = (d.status || '').toLowerCase();
  const dataInicio = parseData(d.data_inicio_status);

  let dias = 0;
  if (dataInicio) {
    dias = Math.floor((hoje - dataInicio) / (1000 * 60 * 60 * 24));
  }

  const limite = limites[status] || 7;

  let prioridade = 'ok';

  if (dias > limite) prioridade = 'urgente';
  else if (dias >= limite * 0.8) prioridade = 'atencao';

  return {
    parceiro: d.parceiro,
    status,
    dias,
    prioridade
  };
});

const urgentes = resultado.filter(r => r.prioridade === 'urgente');
const atencao = resultado.filter(r => r.prioridade === 'atencao');
const ok = resultado.filter(r => r.prioridade === 'ok');

return [{
  json: {
    urgentes,
    atencao,
    ok
  }
}];
